import 'dart:convert';
import 'package:flutter/material.dart'; import 'package:http/http.dart' as http; import 'package:shared_preferences/shared_preferences.dart'; import 'package:url_launcher/url_launcher.dart';
class WalletScreen extends StatefulWidget{const WalletScreen({super.key});@override State<WalletScreen> createState()=>_WalletScreenState();}
class _WalletScreenState extends State<WalletScreen>{static const baseUrl='https://api.servicepay.ng/api';final amountController=TextEditingController();final referenceController=TextEditingController();bool isLoading=false;double walletBalance=0;@override void initState(){super.initState();refreshWallet();}@override void dispose(){amountController.dispose();referenceController.dispose();super.dispose();}void msg(String m){if(mounted)ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text(m)));}Future<Map<String,String>> headers()async{final p=await SharedPreferences.getInstance();return {'Content-Type':'application/json','Authorization':'Bearer ${p.getString('auth_token')??''}'};}Future<void> refreshWallet()async{try{final r=await http.get(Uri.parse('$baseUrl/wallet'),headers:await headers());final j=jsonDecode(r.body);if(r.statusCode==200&&j['success']==true){final b=(num.tryParse(j['data']['walletBalance'].toString())??0).toDouble();final p=await SharedPreferences.getInstance();await p.setDouble('wallet_balance',b);if(mounted)setState(()=>walletBalance=b);}}catch(_){final p=await SharedPreferences.getInstance();if(mounted)setState(()=>walletBalance=p.getDouble('wallet_balance')??0);}}Future<void> fund()async{final a=double.tryParse(amountController.text.trim());if(a==null||a<100){msg('Minimum wallet funding is ₦100.');return;}setState(()=>isLoading=true);try{final p=await SharedPreferences.getInstance();final r=await http.post(Uri.parse('$baseUrl/paystack/initialize'),headers:await headers(),body:jsonEncode({'email':p.getString('user_email'),'amount':a}));final j=jsonDecode(r.body);if(r.statusCode==200&&j['success']==true){referenceController.text=j['reference']??'';await launchUrl(Uri.parse(j['authorizationUrl']),mode:LaunchMode.externalApplication);msg('Complete payment, return here, then tap Verify Payment.');}else{msg(j['message']??'Unable to initialize payment.');}}catch(_){msg('Unable to connect to Servicepay server.');}finally{if(mounted)setState(()=>isLoading=false);}}Future<void> verify()async{final ref=referenceController.text.trim();if(ref.isEmpty){msg('Enter the Paystack reference.');return;}setState(()=>isLoading=true);try{final r=await http.post(Uri.parse('$baseUrl/paystack/verify'),headers:await headers(),body:jsonEncode({'reference':ref}));final j=jsonDecode(r.body);msg(j['message']??'Verification completed.');if(r.statusCode==200&&j['success']==true){await refreshWallet();amountController.clear();}}catch(_){msg('Unable to verify payment.');}finally{if(mounted)setState(()=>isLoading=false);}}@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Wallet'),backgroundColor:Colors.green,foregroundColor:Colors.white,actions:[IconButton(onPressed:refreshWallet,icon:const Icon(Icons.refresh))]),body:ListView(padding:const EdgeInsets.all(20),children:[Container(padding:const EdgeInsets.all(24),decoration:BoxDecoration(color:Colors.green,borderRadius:BorderRadius.circular(20)),child:Column(children:[const Text('Wallet Balance',style:TextStyle(color:Colors.white70)),const SizedBox(height:8),Text('₦${walletBalance.toStringAsFixed(2)}',style:const TextStyle(color:Colors.white,fontSize:32,fontWeight:FontWeight.bold))])),const SizedBox(height:24),TextField(controller:amountController,keyboardType:TextInputType.number,decoration:const InputDecoration(labelText:'Funding amount',prefixText:'₦ ',border:OutlineInputBorder())),const SizedBox(height:14),ElevatedButton(onPressed:isLoading?null:fund,style:ElevatedButton.styleFrom(backgroundColor:Colors.green,foregroundColor:Colors.white,padding:const EdgeInsets.all(16)),child:const Text('Pay with Card or Bank')),const SizedBox(height:28),const Text('Verify completed payment',style:TextStyle(fontSize:18,fontWeight:FontWeight.bold)),const SizedBox(height:10),TextField(controller:referenceController,decoration:const InputDecoration(labelText:'Paystack reference',border:OutlineInputBorder())),const SizedBox(height:14),OutlinedButton(onPressed:isLoading?null:verify,child:const Text('Verify Payment and Update Wallet'))]));}
